#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-04

# test-mcp-overhead.sh — CI regression gate for MCP scoping (#945)
#
# Asserts:
#   1. Every agent .md file has an explicit mcpServers field
#   2. All Haiku model agents have ≤ 5 MCP servers
#   3. notebooklm-mcp is absent from non-notebook agent mcpServers
#
# Exit 1 on any violation. Runs in CI (validate.yml).

set -euo pipefail

AGENTS_DIR="$(cd "$(dirname "$0")/../../src/agents" && pwd)"
FAIL=0

check() {
  local agent="$1"
  local name
  name="$(basename "$agent" .md)"

  # 1. Must have explicit mcpServers field
  if ! grep -q "^mcpServers:" "$agent"; then
    echo "FAIL [$name]: missing mcpServers field" >&2
    FAIL=1
    return
  fi

  # Extract mcpServers value (single-line array only: mcpServers: [a, b, c])
  local mcp_line
  mcp_line="$(grep "^mcpServers:" "$agent")"
  local mcp_value="${mcp_line#mcpServers:}"
  mcp_value="${mcp_value// /}"  # strip spaces

  # Count servers (comma-separated inside brackets)
  local count=0
  if [[ "$mcp_value" == "[]" ]] || [[ -z "$mcp_value" ]]; then
    count=0
  else
    # Remove brackets and count commas + 1
    local inner="${mcp_value//[/}"
    inner="${inner//]/}"
    if [[ -n "$inner" ]]; then
      count=$(echo "$inner" | tr ',' '\n' | grep -c '\S' || true)
    fi
  fi

  # 2. Haiku agents must have ≤ 5 MCP servers
  if grep -q "^model: haiku" "$agent" 2>/dev/null; then
    if [[ "$count" -gt 5 ]]; then
      echo "FAIL [$name]: Haiku agent has $count MCP servers (max 5)" >&2
      FAIL=1
    fi
  fi

  # 3. notebooklm-mcp only allowed for notebook-related agents
  local allowed_nlm_agents="release-notebook demo-producer"
  if echo "$mcp_value" | grep -q "notebooklm"; then
    if ! echo "$allowed_nlm_agents" | grep -qw "$name"; then
      echo "FAIL [$name]: notebooklm-mcp in mcpServers (allowed only for: $allowed_nlm_agents)" >&2
      FAIL=1
    fi
  fi
}

echo "=== MCP Overhead Regression Gate (#945) ==="
echo "Scanning $(ls "$AGENTS_DIR"/*.md | wc -l | tr -d ' ') agents..."

for agent_file in "$AGENTS_DIR"/*.md; do
  check "$agent_file"
done

if [[ "$FAIL" -eq 0 ]]; then
  echo "PASS: All agents have explicit mcpServers, Haiku agents ≤ 5 tools, notebooklm-mcp scoped correctly."
  exit 0
else
  echo "FAIL: MCP overhead regression detected. Fix the issues above." >&2
  exit 1
fi
